vector<int> empower(const vector<int>& levels) {
    vector<int> out;
    for (int lvl : levels) {
        if (lvl >= 10) out.push_back(lvl * 2);
    }
    return out;
}

int main() {
    int n;
    cin >> n;
    vector<int> levels(n);
    for (int i = 0; i < n; i++) cin >> levels[i];
    vector<int> result = empower(levels);
    bool first = true;
    for (int v : result) {
        if (!first) cout << " ";
        cout << v;
        first = false;
    }
    cout << "\n";
    return 0;
}

