#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

struct Hero {
    string name;
    int hp;

    void take_damage(int n) {
        hp = max(0, hp - n);
    }
    void heal(int n) {
        hp += n;
    }
    bool is_alive() {
        return hp > 0;
    }
};

int main() {
    string name; int hp;
    cin >> name >> hp;
    Hero h{name, hp};
    int k;
    cin >> k;
    for (int i = 0; i < k; i++) {
        string cmd; int amt;
        cin >> cmd >> amt;
        if (cmd == "damage") h.take_damage(amt);
        else h.heal(amt);
    }
    cout << h.hp << "\n";
    cout << (h.is_alive() ? "alive" : "dead") << "\n";
    return 0;
}

