#include <iostream>
#include <string>
#include <unordered_map>
#include <algorithm>
using namespace std;

int main() {
    string s;
    getline(cin, s);
    unordered_map<char,int> last;
    int start = 0, best = 0;
    for (int i = 0; i < (int)s.size(); i++) {
        char ch = s[i];
        if (last.count(ch) && last[ch] >= start)
            start = last[ch] + 1;
        last[ch] = i;
        best = max(best, i - start + 1);
    }
    cout << best << "\n";
    return 0;
}
